∩╗┐import React, { useState, useRef, useEffect } from 'react';
import {
  View, Text, TextInput, TouchableOpacity, StyleSheet,
  KeyboardAvoidingView, Platform, Alert, ActivityIndicator,
  Animated, StatusBar, ScrollView, Easing, Image,
} from 'react-native';
import { useRouter } from 'expo-router';
import { useAuth } from '../../contexts/AuthContext';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';

export default function LoginScreen() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const router = useRouter();

  // Animations
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const slideAnim = useRef(new Animated.Value(40)).current;
  const glowAnim = useRef(new Animated.Value(0.4)).current;

  useEffect(() => {
    Animated.parallel([
      Animated.timing(fadeAnim, { toValue: 1, duration: 900, useNativeDriver: true }),
      Animated.timing(slideAnim, { toValue: 0, duration: 700, easing: Easing.out(Easing.cubic), useNativeDriver: true }),
    ]).start();
    Animated.loop(
      Animated.sequence([
        Animated.timing(glowAnim, { toValue: 1, duration: 2000, useNativeDriver: true }),
        Animated.timing(glowAnim, { toValue: 0.4, duration: 2000, useNativeDriver: true }),
      ])
    ).start();
  }, []);

  const handleLogin = async () => {
    if (!email || !email.includes('@')) {
      return Alert.alert('Invalid Email', 'Please enter a valid email address.');
    }
    if (!password || password.length < 6) {
      return Alert.alert('Invalid Password', 'Password must be at least 6 characters.');
    }
    setLoading(true);
    try {
      await login(email, password);
      router.replace('/(tabs)/home');
    } catch (err: any) {
      Alert.alert('Login Failed', err.message || 'Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={s.container}>
      <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />

      {/* Decorative gradient background */}
      <LinearGradient
        colors={['#0a0a12', '#0e0e1a', '#0a0a12']}
        style={StyleSheet.absoluteFillObject}
      />
      {/* Top accent circles */}
      <View style={s.accentCircle1} />
      <View style={s.accentCircle2} />

      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={s.keyboardView}
      >
        <ScrollView
          contentContainerStyle={s.scrollContent}
          keyboardShouldPersistTaps="handled"
          showsVerticalScrollIndicator={false}
        >
          <Animated.View style={[s.content, { opacity: fadeAnim, transform: [{ translateY: slideAnim }] }]}>
            {/* Logo */}
            <View style={s.logoSection}>
              <Animated.View style={[s.glowRing, { opacity: glowAnim }]} />
              <Image
                source={require('../../assets/images/crimzo-icon.png')}
                style={s.logoIcon}
                resizeMode="contain"
              />
              <Image
                source={require('../../assets/images/crimzo-logo.png')}
                style={s.logoImg}
                resizeMode="contain"
              />
              <Text style={s.logoSub}>WELCOME BACK</Text>
            </View>

            {/* Login Card */}
            <View style={s.card}>
              <Text style={s.cardTitle}>Sign In</Text>
              <Text style={s.cardSub}>Enter your email and password to continue</Text>

              {/* Email */}
              <View style={s.inputWrap}>
                <Ionicons name="mail-outline" size={18} color="rgba(255,255,255,0.35)" style={s.inputIcon} />
                <TextInput
                  style={s.input}
                  placeholder="Email address"
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  value={email}
                  onChangeText={setEmail}
                  autoCapitalize="none"
                  keyboardType="email-address"
                  selectionColor="#9333EA"
                />
              </View>

              {/* Password */}
              <View style={s.inputWrap}>
                <Ionicons name="lock-closed-outline" size={18} color="rgba(255,255,255,0.35)" style={s.inputIcon} />
                <TextInput
                  style={s.input}
                  placeholder="Password"
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  value={password}
                  onChangeText={setPassword}
                  secureTextEntry={!showPassword}
                  selectionColor="#9333EA"
                />
                <TouchableOpacity onPress={() => setShowPassword(!showPassword)} style={s.eyeBtn}>
                  <Ionicons name={showPassword ? 'eye-off-outline' : 'eye-outline'} size={18} color="rgba(255,255,255,0.4)" />
                </TouchableOpacity>
              </View>

              {/* Login Button */}
              <TouchableOpacity style={s.btnWrap} onPress={handleLogin} disabled={loading} activeOpacity={0.8}>
                <LinearGradient
                  colors={['#9333EA', '#A855F7']}
                  start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }}
                  style={s.btnGradient}
                >
                  {loading ? (
                    <ActivityIndicator color="#FFF" />
                  ) : (
                    <View style={s.btnRow}>
                      <Ionicons name="log-in-outline" size={20} color="#FFF" />
                      <Text style={s.btnText}>Sign In</Text>
                    </View>
                  )}
                </LinearGradient>
              </TouchableOpacity>

              {/* Forgot password placeholder */}
              <TouchableOpacity style={s.forgotBtn}>
                <Text style={s.forgotText}>Forgot Password?</Text>
              </TouchableOpacity>
            </View>

            {/* Register link */}
            <View style={s.footer}>
              <Text style={s.footerText}>Don't have an account? </Text>
              <TouchableOpacity onPress={() => router.push('/(auth)/register')}>
                <Text style={s.footerLink}>Sign Up</Text>
              </TouchableOpacity>
            </View>

            <Text style={s.terms}>
              By continuing, you agree to Crimzo's{'\n'}
              <Text style={s.termsLink}>Terms of Service</Text>
              {' & '}
              <Text style={s.termsLink}>Privacy Policy</Text>
            </Text>
          </Animated.View>
        </ScrollView>
      </KeyboardAvoidingView>
    </View>
  );
}

const s = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#08080C' },
  keyboardView: { flex: 1 },
  scrollContent: { flexGrow: 1, justifyContent: 'center', paddingBottom: 32 },
  content: { paddingHorizontal: 24, alignItems: 'center' },

  // Decorative
  accentCircle1: {
    position: 'absolute', top: -80, right: -60,
    width: 200, height: 200, borderRadius: 100,
    backgroundColor: 'rgba(255,45,85,0.06)',
  },
  accentCircle2: {
    position: 'absolute', bottom: -100, left: -80,
    width: 250, height: 250, borderRadius: 125,
    backgroundColor: 'rgba(124,77,255,0.04)',
  },

  // Logo
  logoSection: { alignItems: 'center', marginBottom: 40, position: 'relative' },
  glowRing: {
    position: 'absolute', width: 140, height: 140, borderRadius: 70,
    backgroundColor: 'rgba(255,45,85,0.08)',
    top: '50%', left: '50%',
    transform: [{ translateX: -70 }, { translateY: -70 }],
  },
  logoText: {
    fontSize: 48, fontWeight: '900', color: '#FFF', letterSpacing: 6,
    textShadowColor: 'rgba(255,45,85,0.3)',
    textShadowOffset: { width: 0, height: 4 }, textShadowRadius: 15,
  },
  logoIcon: {
    width: 64, height: 64, marginBottom: 10,
  },
  logoImg: {
    width: 160, height: 40, marginBottom: 4,
  },
  logoSub: {
    fontSize: 12, color: 'rgba(255,255,255,0.5)', letterSpacing: 4,
    marginTop: 8, fontWeight: '600',
  },

  // Card
  card: {
    width: '100%', backgroundColor: 'rgba(18,18,28,0.8)',
    borderRadius: 28, padding: 28,
    borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)',
  },
  cardTitle: { fontSize: 24, fontWeight: '800', color: '#FFF', marginBottom: 6 },
  cardSub: { fontSize: 14, color: 'rgba(255,255,255,0.4)', marginBottom: 24, lineHeight: 20 },

  // Input
  inputWrap: {
    flexDirection: 'row', alignItems: 'center', height: 56,
    backgroundColor: 'rgba(0,0,0,0.4)', borderRadius: 16,
    borderWidth: 1, borderColor: 'rgba(255,255,255,0.08)',
    marginBottom: 14, overflow: 'hidden',
  },
  inputIcon: { marginLeft: 16 },
  input: { flex: 1, color: '#FFF', fontSize: 15, paddingHorizontal: 12, fontWeight: '500' },
  eyeBtn: { paddingHorizontal: 14 },

  // Button
  btnWrap: {
    width: '100%', height: 56, borderRadius: 18, overflow: 'hidden', marginTop: 4,
    shadowColor: '#9333EA', shadowOffset: { width: 0, height: 6 },
    shadowOpacity: 0.35, shadowRadius: 12, elevation: 8,
  },
  btnGradient: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  btnRow: { flexDirection: 'row', alignItems: 'center', gap: 8 },
  btnText: { color: '#FFF', fontSize: 17, fontWeight: '700', letterSpacing: 0.3 },

  forgotBtn: { alignItems: 'center', marginTop: 16 },
  forgotText: { color: 'rgba(255,255,255,0.4)', fontSize: 13, fontWeight: '600' },

  // Footer
  footer: {
    flexDirection: 'row', alignItems: 'center', justifyContent: 'center',
    marginTop: 28,
  },
  footerText: { color: 'rgba(255,255,255,0.4)', fontSize: 14 },
  footerLink: { color: '#9333EA', fontSize: 14, fontWeight: '700' },

  terms: {
    color: 'rgba(255,255,255,0.25)', fontSize: 11, textAlign: 'center',
    lineHeight: 17, marginTop: 20,
  },
  termsLink: { color: 'rgba(255,255,255,0.5)', fontWeight: '600' },
});

import React, { useState, useRef, useEffect } from 'react';
import {
  View, Text, TextInput, TouchableOpacity, StyleSheet,
  KeyboardAvoidingView, Platform, Alert, ActivityIndicator,
  Animated, StatusBar, ScrollView, Image, Easing, Modal,
} from 'react-native';
import { useRouter } from 'expo-router';
import { useAuth } from '../../contexts/AuthContext';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import * as ImagePicker from 'expo-image-picker';

export default function RegisterScreen() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [username, setUsername] = useState('');
  const [avatarUri, setAvatarUri] = useState<string | null>(null);
  const [showAvatarPreview, setShowAvatarPreview] = useState(false);
  const [tempAvatarUri, setTempAvatarUri] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const { register } = useAuth();
  const router = useRouter();

  // Animations
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const slideAnim = useRef(new Animated.Value(40)).current;
  const glowAnim = useRef(new Animated.Value(0.4)).current;

  useEffect(() => {
    Animated.parallel([
      Animated.timing(fadeAnim, { toValue: 1, duration: 900, useNativeDriver: true }),
      Animated.timing(slideAnim, { toValue: 0, duration: 700, easing: Easing.out(Easing.cubic), useNativeDriver: true }),
    ]).start();
    Animated.loop(
      Animated.sequence([
        Animated.timing(glowAnim, { toValue: 1, duration: 2000, useNativeDriver: true }),
        Animated.timing(glowAnim, { toValue: 0.4, duration: 2000, useNativeDriver: true }),
      ])
    ).start();
  }, []);

  const pickAvatar = async () => {
    try {
      const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
      if (status !== 'granted') {
        return Alert.alert('Permission Required', 'Please grant access to your photo library.');
      }
      const result = await ImagePicker.launchImageLibraryAsync({
        mediaTypes: ['images'],
        allowsEditing: true,
        aspect: [1, 1],
        quality: 0.8,
      });
      if (!result.canceled && result.assets?.[0]) {
        setTempAvatarUri(result.assets[0].uri);
        setShowAvatarPreview(true);
      }
    } catch (err) {
      console.error('Image picker error:', err);
    }
  };

  const confirmAvatar = () => {
    setAvatarUri(tempAvatarUri);
    setShowAvatarPreview(false);
    setTempAvatarUri(null);
  };

  const retakeAvatar = async () => {
    setShowAvatarPreview(false);
    setTempAvatarUri(null);
    setTimeout(() => pickAvatar(), 300);
  };

  const handleRegister = async () => {
    if (!username || username.trim().length < 3) {
      return Alert.alert('Invalid Username', 'Username must be at least 3 characters.');
    }
    if (!email || !email.includes('@')) {
      return Alert.alert('Invalid Email', 'Please enter a valid email address.');
    }
    if (!password || password.length < 6) {
      return Alert.alert('Weak Password', 'Password must be at least 6 characters.');
    }
    if (password !== confirmPassword) {
      return Alert.alert('Password Mismatch', 'Passwords do not match.');
    }

    setLoading(true);
    try {
      await register(email, password, username, avatarUri || undefined);
      router.replace('/(tabs)/home');
    } catch (err: any) {
      Alert.alert('Registration Failed', err.message || 'Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={s.container}>
      <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />

      <LinearGradient
        colors={['#0a0a12', '#0e0e1a', '#0a0a12']}
        style={StyleSheet.absoluteFillObject}
      />
      <View style={s.accentCircle1} />
      <View style={s.accentCircle2} />

      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={s.keyboardView}
      >
        <ScrollView
          contentContainerStyle={s.scrollContent}
          keyboardShouldPersistTaps="handled"
          showsVerticalScrollIndicator={false}
        >
          {/* Back */}
          <TouchableOpacity style={s.backBtn} onPress={() => router.back()}>
            <View style={s.backBtnInner}>
              <Ionicons name="arrow-back" size={22} color="#FFF" />
            </View>
          </TouchableOpacity>

          <Animated.View style={[s.content, { opacity: fadeAnim, transform: [{ translateY: slideAnim }] }]}>
            {/* Logo */}
            <View style={s.logoSection}>
              <Animated.View style={[s.glowRing, { opacity: glowAnim }]} />
              <Image
                source={require('../../assets/images/crimzo-icon.png')}
                style={s.logoIcon}
                resizeMode="contain"
              />
              <Image
                source={require('../../assets/images/crimzo-logo.png')}
                style={s.logoImg}
                resizeMode="contain"
              />
              <Text style={s.logoSub}>CREATE YOUR ACCOUNT</Text>
            </View>

            {/* Card */}
            <View style={s.card}>
              {/* Avatar Picker */}
              <TouchableOpacity style={s.avatarPicker} onPress={pickAvatar} activeOpacity={0.7}>
                {avatarUri ? (
                  <Image source={{ uri: avatarUri }} style={s.avatarImage} />
                ) : (
                  <View style={s.avatarPlaceholder}>
                    <Ionicons name="camera" size={28} color="rgba(255,255,255,0.4)" />
                  </View>
                )}
                <View style={s.avatarBadge}>
                  <Ionicons name="add" size={14} color="#FFF" />
                </View>
                <Text style={s.avatarLabel}>Profile Photo</Text>
              </TouchableOpacity>

              {/* Username */}
              <View style={s.inputWrap}>
                <Ionicons name="person-outline" size={18} color="rgba(255,255,255,0.35)" style={s.inputIcon} />
                <TextInput
                  style={s.input}
                  placeholder="Username (min 3 chars)"
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  value={username}
                  onChangeText={(t) => setUsername(t.replace(/\s/g, ''))}
                  autoCapitalize="none"
                  selectionColor="#9333EA"
                />
              </View>

              {/* Email */}
              <View style={s.inputWrap}>
                <Ionicons name="mail-outline" size={18} color="rgba(255,255,255,0.35)" style={s.inputIcon} />
                <TextInput
                  style={s.input}
                  placeholder="Email address"
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  value={email}
                  onChangeText={setEmail}
                  autoCapitalize="none"
                  keyboardType="email-address"
                  selectionColor="#9333EA"
                />
              </View>

              {/* Password */}
              <View style={s.inputWrap}>
                <Ionicons name="lock-closed-outline" size={18} color="rgba(255,255,255,0.35)" style={s.inputIcon} />
                <TextInput
                  style={s.input}
                  placeholder="Password (min 6 chars)"
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  value={password}
                  onChangeText={setPassword}
                  secureTextEntry={!showPassword}
                  selectionColor="#9333EA"
                />
                <TouchableOpacity onPress={() => setShowPassword(!showPassword)} style={s.eyeBtn}>
                  <Ionicons name={showPassword ? 'eye-off-outline' : 'eye-outline'} size={18} color="rgba(255,255,255,0.4)" />
                </TouchableOpacity>
              </View>

              {/* Confirm Password */}
              <View style={s.inputWrap}>
                <Ionicons name="lock-closed-outline" size={18} color="rgba(255,255,255,0.35)" style={s.inputIcon} />
                <TextInput
                  style={s.input}
                  placeholder="Confirm Password"
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  value={confirmPassword}
                  onChangeText={setConfirmPassword}
                  secureTextEntry={!showPassword}
                  selectionColor="#9333EA"
                />
              </View>

              {/* Register Button */}
              <TouchableOpacity style={s.btnWrap} onPress={handleRegister} disabled={loading} activeOpacity={0.8}>
                <LinearGradient
                  colors={['#9333EA', '#A855F7']}
                  start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }}
                  style={s.btnGradient}
                >
                  {loading ? (
                    <ActivityIndicator color="#FFF" />
                  ) : (
                    <View style={s.btnRow}>
                      <Ionicons name="sparkles" size={19} color="#FFF" />
                      <Text style={s.btnText}>Create Account</Text>
                    </View>
                  )}
                </LinearGradient>
              </TouchableOpacity>
            </View>

            {/* Login link */}
            <View style={s.footer}>
              <Text style={s.footerText}>Already have an account? </Text>
              <TouchableOpacity onPress={() => router.back()}>
                <Text style={s.footerLink}>Sign In</Text>
              </TouchableOpacity>
            </View>

            <Text style={s.terms}>
              By creating an account, you agree to Crimzo's{'\n'}
              <Text style={s.termsLink}>Terms of Service</Text>
              {' & '}
              <Text style={s.termsLink}>Privacy Policy</Text>
            </Text>
          </Animated.View>
        </ScrollView>
      </KeyboardAvoidingView>

      {/* Avatar Preview Modal */}
      <Modal visible={showAvatarPreview} animationType="fade" transparent statusBarTranslucent>
        <View style={s.avatarModalOverlay}>
          <View style={s.avatarModalContent}>
            <Text style={s.avatarModalTitle}>Profile Photo</Text>
            {tempAvatarUri && (
              <Image source={{ uri: tempAvatarUri }} style={s.avatarModalImage} />
            )}
            <View style={s.avatarModalActions}>
              <TouchableOpacity style={s.avatarModalBtn} onPress={retakeAvatar}>
                <Ionicons name="crop" size={20} color="#9333EA" />
                <Text style={s.avatarModalBtnText}>Re-crop</Text>
              </TouchableOpacity>
              <TouchableOpacity style={[s.avatarModalBtn, s.avatarModalDoneBtn]} onPress={confirmAvatar}>
                <Ionicons name="checkmark-circle" size={20} color="#FFF" />
                <Text style={[s.avatarModalBtnText, { color: '#FFF' }]}>Done</Text>
              </TouchableOpacity>
            </View>
            <TouchableOpacity style={s.avatarModalCancel} onPress={() => { setShowAvatarPreview(false); setTempAvatarUri(null); }}>
              <Text style={s.avatarModalCancelText}>Cancel</Text>
            </TouchableOpacity>
          </View>
        </View>
      </Modal>
    </View>
  );
}

const s = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#08080C' },
  keyboardView: { flex: 1 },
  scrollContent: { flexGrow: 1, justifyContent: 'center', paddingBottom: 32 },
  content: { paddingHorizontal: 24, alignItems: 'center' },

  // Decorative
  accentCircle1: {
    position: 'absolute', top: -80, right: -60,
    width: 200, height: 200, borderRadius: 100,
    backgroundColor: 'rgba(255,45,85,0.06)',
  },
  accentCircle2: {
    position: 'absolute', bottom: -100, left: -80,
    width: 250, height: 250, borderRadius: 125,
    backgroundColor: 'rgba(124,77,255,0.04)',
  },

  // Back
  backBtn: {
    position: 'absolute', top: Platform.OS === 'ios' ? 56 : 44,
    left: 16, zIndex: 10,
  },
  backBtnInner: {
    width: 40, height: 40, borderRadius: 20,
    backgroundColor: 'rgba(255,255,255,0.1)',
    alignItems: 'center', justifyContent: 'center',
  },

  // Logo
  logoSection: { alignItems: 'center', marginBottom: 28, position: 'relative' },
  glowRing: {
    position: 'absolute', width: 120, height: 120, borderRadius: 60,
    backgroundColor: 'rgba(255,45,85,0.08)',
    top: '50%', left: '50%',
    transform: [{ translateX: -60 }, { translateY: -60 }],
  },
  logoText: {
    fontSize: 42, fontWeight: '900', color: '#FFF', letterSpacing: 5,
    textShadowColor: 'rgba(255,45,85,0.3)',
    textShadowOffset: { width: 0, height: 4 }, textShadowRadius: 15,
  },
  logoIcon: {
    width: 56, height: 56, marginBottom: 8,
  },
  logoImg: {
    width: 140, height: 36, marginBottom: 4,
  },
  logoSub: {
    fontSize: 11, color: 'rgba(255,255,255,0.5)', letterSpacing: 3,
    marginTop: 6, fontWeight: '600',
  },

  // Card
  card: {
    width: '100%', backgroundColor: 'rgba(18,18,28,0.8)',
    borderRadius: 28, padding: 24,
    borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)',
  },

  // Avatar
  avatarPicker: { alignItems: 'center', marginBottom: 20, position: 'relative' },
  avatarImage: { width: 90, height: 90, borderRadius: 45, borderWidth: 3, borderColor: '#9333EA' },
  avatarPlaceholder: {
    width: 90, height: 90, borderRadius: 45,
    backgroundColor: 'rgba(255,255,255,0.06)',
    borderWidth: 2, borderColor: 'rgba(255,255,255,0.1)', borderStyle: 'dashed',
    alignItems: 'center', justifyContent: 'center',
  },
  avatarBadge: {
    position: 'absolute', bottom: 18, right: '50%',
    marginRight: -45,
    width: 26, height: 26, borderRadius: 13,
    backgroundColor: '#9333EA', alignItems: 'center', justifyContent: 'center',
    borderWidth: 2.5, borderColor: '#0a0a12',
  },
  avatarLabel: {
    color: 'rgba(255,255,255,0.4)', fontSize: 12, fontWeight: '600', marginTop: 8,
  },

  // Input
  inputWrap: {
    flexDirection: 'row', alignItems: 'center', height: 54,
    backgroundColor: 'rgba(0,0,0,0.4)', borderRadius: 16,
    borderWidth: 1, borderColor: 'rgba(255,255,255,0.08)',
    marginBottom: 12, overflow: 'hidden',
  },
  inputIcon: { marginLeft: 16 },
  input: { flex: 1, color: '#FFF', fontSize: 15, paddingHorizontal: 12, fontWeight: '500' },
  eyeBtn: { paddingHorizontal: 14 },

  // Button
  btnWrap: {
    width: '100%', height: 56, borderRadius: 18, overflow: 'hidden', marginTop: 6,
    shadowColor: '#9333EA', shadowOffset: { width: 0, height: 6 },
    shadowOpacity: 0.35, shadowRadius: 12, elevation: 8,
  },
  btnGradient: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  btnRow: { flexDirection: 'row', alignItems: 'center', gap: 8 },
  btnText: { color: '#FFF', fontSize: 17, fontWeight: '700', letterSpacing: 0.3 },

  // Footer
  footer: {
    flexDirection: 'row', alignItems: 'center', justifyContent: 'center',
    marginTop: 24,
  },
