    paddingVertical: 15, borderRadius: 14,
  },
  uploadBtnText: { color: '#FFF', fontSize: 16, fontWeight: '700' },
});

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Reel Preview Modal (Instagram-style full-screen)
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ReelPreviewModal({
  visible,
  asset,
  uploading,
  uploadProgress,
  uploadDone,
  onClose,
  onPost,
}: {
  visible: boolean;
  asset: any;
  uploading: boolean;
  uploadProgress: number;
  uploadDone: boolean;
  onClose: () => void;
  onPost: (caption: string) => void;
}) {
  const [caption, setCaption] = useState('');
  const player = useVideoPlayer(asset?.uri ?? null, (p) => {
    p.loop = true;
    p.muted = false;
  });

  useEffect(() => {
    if (visible && asset?.uri) {
      try { player.play(); } catch (_) {}
    } else {
      try { player.pause(); } catch (_) {}
    }
  }, [visible, asset?.uri]);

  if (!visible) return null;

  return (
    <Modal visible={visible} animationType="slide" statusBarTranslucent>
      <View style={rpmStyles.container}>
        <StatusBar barStyle="light-content" />

        {/* Header */}
        <View style={rpmStyles.header}>
          <TouchableOpacity onPress={onClose} style={rpmStyles.closeBtn} disabled={uploading}>
            <Ionicons name="arrow-back" size={24} color="#FFF" />
          </TouchableOpacity>
          <Text style={rpmStyles.title}>New Reel</Text>
          <View style={{ width: 40 }} />
        </View>

        {/* Video preview fills the screen */}
        <View style={rpmStyles.videoWrapper}>
          {asset?.uri ? (
            <VideoView
              player={player}
              style={StyleSheet.absoluteFill}
              contentFit="cover"
              nativeControls={false}
            />
