import React, { useEffect, useState, useCallback } from 'react';
import { View, StyleSheet, Alert, Platform } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useRouter, useFocusEffect } from 'expo-router';
import { useAuth } from '../../contexts/AuthContext';
import axios from 'axios';
import * as ImagePicker from 'expo-image-picker';
import StoryViewer from '../../components/StoryViewer';
import { UploadOverlay } from '../../components/create';
import {
  HomeHeader,
  StoriesRow,
  LiveUsersRow,
  HomeTabs,
  LiveStreamGrid,
} from '../../components/home';

const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;

export default function HomeScreen() {
  const { user, token } = useAuth();
  const router = useRouter();
  const [activeTab, setActiveTab] = useState('for-you');
  const [liveStreams, setLiveStreams] = useState([]);
  const [liveUsers, setLiveUsers] = useState<any[]>([]);
  const [onlineCount, setOnlineCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  // Stories state
  const [storyGroups, setStoryGroups] = useState<any[]>([]);
  const [showStoryViewer, setShowStoryViewer] = useState(false);
  const [storyViewerIndex, setStoryViewerIndex] = useState(0);
  const [uploadingStory, setUploadingStory] = useState(false);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchLiveUsers, 10000);
    return () => clearInterval(interval);
  }, []);

  useFocusEffect(
    useCallback(() => {
      fetchLiveUsers();
      fetchStories();
    }, [])
  );

  // ΓöÇΓöÇ Data fetching ΓöÇΓöÇ
  const fetchLiveUsers = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/live/users`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setLiveUsers(res.data.liveUsers || []);
    } catch (error) {
      console.error('Fetch live users error:', error);
    }
  };

  const fetchStories = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/stories`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setStoryGroups(res.data.storyGroups || []);
    } catch (error) {
      console.error('Fetch stories error:', error);
    }
  };

  const fetchData = async () => {
    try {
      const [streamsRes, countRes, liveUsersRes, storiesRes] = await Promise.all([
        axios.get(`${API_URL}/api/live/active`, { headers: { Authorization: `Bearer ${token}` } }),
        axios.get(`${API_URL}/api/users/online-count`, { headers: { Authorization: `Bearer ${token}` } }),
        axios.get(`${API_URL}/api/live/users`, { headers: { Authorization: `Bearer ${token}` } }),
        axios.get(`${API_URL}/api/stories`, { headers: { Authorization: `Bearer ${token}` } }),
      ]);

      setLiveStreams(streamsRes.data.streams || []);
      setOnlineCount(countRes.data.count || 0);
      setLiveUsers(liveUsersRes.data.liveUsers || []);
      setStoryGroups(storiesRes.data.storyGroups || []);
    } catch (error) {
      console.error('Fetch data error:', error);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  const onRefresh = () => {
    setRefreshing(true);
    fetchData();
  };

  // ΓöÇΓöÇ Story actions ΓöÇΓöÇ
  const handleAddStory = async () => {
    try {
      const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert('Permission Required', 'Please grant access to your media library to upload stories.');
        return;
      }

      const result = await ImagePicker.launchImageLibraryAsync({
        mediaTypes: ['images', 'videos'],
        allowsEditing: true,
        quality: 0.8,
        videoMaxDuration: 30,
      });

      if (result.canceled || !result.assets || result.assets.length === 0) return;

      const asset = result.assets[0];
      const isVideo = asset.type === 'video';

      setUploadingStory(true);

      const formData = new FormData();
      const uri = asset.uri;
      const filename = uri.split('/').pop() || `story_${Date.now()}.${isVideo ? 'mp4' : 'jpg'}`;
      formData.append('media', {
        uri: Platform.OS === 'android' ? uri : uri.replace('file://', ''),
        name: filename,
        type: isVideo ? 'video/mp4' : 'image/jpeg',
      } as any);

      const response = await axios.post(`${API_URL}/api/stories/upload`, formData, {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'multipart/form-data',
        },
        timeout: 60000,
      });

      if (response.data.success) {
        fetchStories();
        Alert.alert('Γ£¿ Story Uploaded!', 'Your story is now visible to everyone for 24 hours.');
      }
    } catch (error: any) {
      console.error('Story upload error:', error);
      Alert.alert('Upload Failed', error.response?.data?.error || 'Something went wrong.');
    } finally {
      setUploadingStory(false);
    }
  };

  const handleDeleteStory = async (storyId: number) => {
    try {
      await axios.delete(`${API_URL}/api/stories/${storyId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchStories();
    } catch (error) {
      console.error('Delete story error:', error);
    }
  };

  const openStoryViewer = (index: number) => {
    setStoryViewerIndex(index);
    setShowStoryViewer(true);
  };

  const hasOwnStory = storyGroups.length > 0 && storyGroups[0]?.user_id === user?.id;

  return (
    <SafeAreaView style={styles.container}>
      <HomeHeader
        username={user?.username || ''}
        onlineCount={onlineCount}
      />

      <StoriesRow
        storyGroups={storyGroups}
        currentUserId={user?.id || 0}
        currentUserAvatar={user?.avatar || null}
        hasOwnStory={hasOwnStory}
        onAddStory={handleAddStory}
        onOpenStoryViewer={openStoryViewer}
      />

      <LiveUsersRow
        liveUsers={liveUsers}
        onWatchStream={(sessionId) => router.push(`/live/watch?sessionId=${sessionId}`)}
      />

      <HomeTabs activeTab={activeTab} onChangeTab={setActiveTab} />

      <LiveStreamGrid
        streams={liveStreams}
        loading={loading}
        refreshing={refreshing}
        onRefresh={onRefresh}
        onWatchStream={(id) => router.push(`/live/watch?sessionId=${id}`)}
        onStartBroadcast={() => router.push('/live/broadcast')}
      />

      <StoryViewer
        visible={showStoryViewer}
        storyGroups={storyGroups}
        initialGroupIndex={storyViewerIndex}
        currentUserId={user?.id || 0}
        onClose={() => setShowStoryViewer(false)}
        onDeleteStory={handleDeleteStory}
      />

      <UploadOverlay visible={uploadingStory} />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#000' },
});

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
