import { useRouter } from 'expo-router';
import { useFocusEffect } from '@react-navigation/native';

const { width: SW } = Dimensions.get('window');
const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;
const REEL_THUMB_W = (SW - 6) / 3;

// ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
//  PROFILE SCREEN  (Instagram-style)
// ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
export default function ProfileScreen() {
  const { user, token, logout, updateUser } = useAuth();
  const router = useRouter();
  const [refreshing, setRefreshing] = useState(false);

  // Follow list
  const [listModalVisible, setListModalVisible] = useState(false);
  const [listType, setListType] = useState<'followers' | 'following'>('followers');
  const [listData, setListData] = useState<any[]>([]);
  const [listLoading, setListLoading] = useState(false);

  // Reels
  const [myReels, setMyReels] = useState<any[]>([]);
  const [reelsLoading, setReelsLoading] = useState(false);

  // Hamburger menu
  const [menuVisible, setMenuVisible] = useState(false);
  const menuSlide = useRef(new Animated.Value(SW)).current;

  // ΓöÇΓöÇ Fetch profile ΓöÇΓöÇ
  const fetchProfile = useCallback(async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/user/profile/full?userId=${user?.id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (data.success && data.profile) {
        updateUser({
          ...user,
          diamonds: data.profile.diamonds,
          beans: data.profile.beans,
          followers_count: data.profile.followers_count,
          following_count: data.profile.following_count,
          friends_count: data.profile.friends_count,
          avatar: data.profile.avatar,
          bio: data.profile.bio,
          country: data.profile.country,
          username: data.profile.username,
        });
      }
    } catch (e) { }
  }, [token, user?.id]);

  // ΓöÇΓöÇ Fetch my reels ΓöÇΓöÇ
  const fetchMyReels = useCallback(async () => {
    if (!token || !user?.id) return;
    setReelsLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/reels/user/${user.id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (data.success) setMyReels(data.reels || []);
    } catch (e) {
      console.error('Fetch my reels error:', e);
    } finally {
      setReelsLoading(false);
    }
  }, [token, user?.id]);

  useFocusEffect(
    useCallback(() => {
      fetchProfile();
      fetchMyReels();
    }, [fetchProfile, fetchMyReels])
  );

  const onRefresh = async () => {
    setRefreshing(true);
    await Promise.all([fetchProfile(), fetchMyReels()]);
    setRefreshing(false);
  };

  // ΓöÇΓöÇ Follow list ΓöÇΓöÇ
  const openFollowList = async (type: 'followers' | 'following') => {
    setListType(type);
    setListModalVisible(true);
    setListLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/user/${type}/${user?.id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (data.success) setListData(data[type] || []);
    } catch (e) {
      console.error(`Fetch ${type} error:`, e);
    } finally {
      setListLoading(false);
    }
  };

  const handleFollowFromList = async (userId: number, index: number) => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/user/follow`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId }),
      });
      const data = await res.json();
      if (data.success) {
        setListData(prev => {
          const updated = [...prev];
          updated[index] = { ...updated[index], is_following: data.action === 'followed' };
          return updated;
        });
        fetchProfile();
      }
    } catch (e) {
      console.error('Follow from list error:', e);
    }
  };

  // ΓöÇΓöÇ Hamburger menu ΓöÇΓöÇ
  const openMenu = () => {
    setMenuVisible(true);
    Animated.spring(menuSlide, { toValue: 0, damping: 22, stiffness: 180, useNativeDriver: true }).start();
  };

  const closeMenu = () => {
    Animated.timing(menuSlide, { toValue: SW, duration: 250, useNativeDriver: true }).start(() => {
      setMenuVisible(false);
    });
  };

  const handleMenuPress = (label: string) => {
    closeMenu();
    setTimeout(() => {
      switch (label) {
        case 'My Profile': router.push('/profile/edit' as any); break;
        case 'Wallet': router.push('/profile/wallet' as any); break;
        case 'Messages': router.push('/profile/messages' as any); break;
        case 'My Tasks':
          router.push('/profile/tasks' as any);
          break;
        case 'My Invitation':
          Alert.alert('Invite Friends', 'Share your invite code!\n\nCode: CRIMZO-' + (user?.id || '000'));
          break;
        case 'Settings': router.push('/profile/settings' as any); break;
        case 'Help & Support':
          Alert.alert('Help & Support', 'Email: support@crimzo.app\nVersion: 1.0.0');
          break;
        default: break;
      }
    }, 300);
  };

  const handleLogout = () => {
    closeMenu();
    setTimeout(() => {
      Alert.alert('Logout', 'Are you sure you want to logout?', [
        { text: 'Cancel', style: 'cancel' },
        { text: 'Logout', style: 'destructive', onPress: async () => { await logout(); router.replace('/(auth)/login'); } },
      ]);
    }, 300);
  };

  const formatNumber = (n: number | undefined) => {
    if (!n) return '0';
    if (n >= 1000000) return (n / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
    if (n >= 1000) return (n / 1000).toFixed(1).replace(/\.0$/, '') + 'K';
    return n.toString();
  };

  const initial = (user?.username || 'U').charAt(0).toUpperCase();

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  //  RENDER
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  return (
    <View style={s.container}>
      <StatusBar barStyle="light-content" />

      <ScrollView
        showsVerticalScrollIndicator={false}
        refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor="#FF2D55" />}
        contentContainerStyle={{ paddingBottom: 80 }}
      >
        {/* ΓöÇΓöÇ Top bar ΓöÇΓöÇ */}
        <View style={s.topBar}>
          <Text style={s.topUsername}>{user?.username || 'User'}</Text>
          <TouchableOpacity style={s.hamburgerBtn} onPress={openMenu}>
            <Ionicons name="menu-outline" size={26} color="#FFF" />
          </TouchableOpacity>
        </View>

        {/* ΓöÇΓöÇ Profile header row (Instagram-style) ΓöÇΓöÇ */}
        <View style={s.profileRow}>
          {/* Avatar */}
          <TouchableOpacity style={s.avatarWrap} onPress={() => router.push('/profile/edit' as any)}>
            <LinearGradient colors={['#FF2D55', '#FF6B8A', '#FFB347']} style={s.avatarRing}>
              <View style={s.avatarInner}>
                {user?.avatar ? (
                  <Image source={{ uri: user.avatar }} style={s.avatar} />
                ) : (
                  <View style={[s.avatar, s.avatarPlaceholder]}>
                    <Text style={s.avatarInitial}>{initial}</Text>
                  </View>
                )}
              </View>
            </LinearGradient>
          </TouchableOpacity>

          {/* Stats row */}
          <View style={s.statsRow}>
            <TouchableOpacity style={s.statBox}>
              <Text style={s.statValue}>{myReels.length}</Text>
              <Text style={s.statLabel}>Posts</Text>
            </TouchableOpacity>
            <TouchableOpacity style={s.statBox} onPress={() => openFollowList('followers')}>
              <Text style={s.statValue}>{formatNumber(user?.followers_count)}</Text>
              <Text style={s.statLabel}>Followers</Text>
            </TouchableOpacity>
            <TouchableOpacity style={s.statBox} onPress={() => openFollowList('following')}>
              <Text style={s.statValue}>{formatNumber(user?.following_count)}</Text>
              <Text style={s.statLabel}>Following</Text>
            </TouchableOpacity>
          </View>
        </View>

        {/* ΓöÇΓöÇ Name & Bio ΓöÇΓöÇ */}
        <View style={s.bioSection}>
          <Text style={s.displayName}>{user?.username || 'User'}</Text>
          {user?.bio ? <Text style={s.bioText}>{user.bio}</Text> : null}
          {user?.country ? (
            <Text style={s.countryText}>≡ƒôì {user.country}</Text>
          ) : null}
        </View>

        {/* ΓöÇΓöÇ Edit Profile & Share ΓöÇΓöÇ */}
        <View style={s.actionRow}>
          <TouchableOpacity style={s.editBtn} onPress={() => router.push('/profile/edit' as any)} activeOpacity={0.7}>
            <Text style={s.editBtnText}>Edit Profile</Text>
          </TouchableOpacity>
          <TouchableOpacity style={s.editBtn} onPress={() => router.push('/profile/wallet' as any)} activeOpacity={0.7}>
            <View style={s.walletRow}>
              <Ionicons name="diamond" size={14} color="#A78BFA" />
              <Text style={s.editBtnText}>{formatNumber(user?.diamonds)}</Text>
            </View>
          </TouchableOpacity>
        </View>

        {/* ΓöÇΓöÇ Reels Grid ΓöÇΓöÇ */}
        <View style={s.reelsHeader}>
          <View style={s.reelsTabActive}>
            <Ionicons name="grid-outline" size={22} color="#FFF" />
          </View>
        </View>

        {reelsLoading ? (
          <View style={s.reelsLoading}>
            <ActivityIndicator size="small" color="#FF2D55" />
