                {reel.thumbnail_url ? (
                  <Image source={{ uri: reel.thumbnail_url }} style={s.reelThumbImg} />
                ) : (
                  <View style={s.reelThumbImg}>
                    <Ionicons name="play" size={24} color="rgba(255,255,255,0.6)" />
                  </View>
                )}
                <View style={s.reelOverlay}>
                  <View style={s.reelStatRow}>
                    <Ionicons name="heart" size={11} color="#FFF" />
                    <Text style={s.reelStatText}>{formatNumber(reel.likes_count || 0)}</Text>
                  </View>
                </View>
              </TouchableOpacity>
