                          {item.is_online && <View style={m.onlineDot} />}
                        </View>
                        {item.bio ? <Text style={m.userBio} numberOfLines={1}>{item.bio}</Text> : null}
                      </View>
                    </View>
                    {item.id !== user?.id && (
                      <TouchableOpacity
                        style={[m.followBtn, item.is_following && m.followingBtn]}
                        onPress={() => handleFollowFromList(item.id, index)}
                      >
                        <Text style={[m.followBtnText, item.is_following && m.followingText]}>
                          {item.is_following ? 'Following' : 'Follow'}
                        </Text>
                      </TouchableOpacity>
                    )}
                  </View>
                )}
              />
            )}
          </View>
        </View>
      </Modal>
    </View>
  );
}

