import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import {
  View,
  Text,
  StyleSheet,
  Dimensions,
  TouchableOpacity,
  Image,
  FlatList,
  ActivityIndicator,
  TextInput,
  KeyboardAvoidingView,
  Platform,
  Animated,
  StatusBar,
  Share,
  RefreshControl,
  Modal,
} from 'react-native';
import { useVideoPlayer, VideoView } from 'expo-video';
import { Ionicons } from '@expo/vector-icons';
import { useAuth } from '../../contexts/AuthContext';
import { LinearGradient } from 'expo-linear-gradient';
import { useFocusEffect } from 'expo-router';
import * as ImagePicker from 'expo-image-picker';
import axios from 'axios';


const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');
const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;

// Tab bar height + bottom inset approximation
const TAB_BAR_HEIGHT = 82;
const REEL_HEIGHT = SCREEN_HEIGHT - TAB_BAR_HEIGHT;

type Reel = {
  id: number;
  user_id: number;
  video_url: string;
  caption: string;
  likes_count: number;
  comments_count: number;
  views_count: number;
  username: string;
  avatar: string | null;
  is_liked: boolean;
  is_following: boolean;
  created_at: string;
};

type Comment = {
  id: number;
  user_id: number;
  text: string;
  username: string;
  avatar: string | null;
  created_at: string;
};

// ΓöÇΓöÇ Single Reel Item Component ΓöÇΓöÇ
function ReelItem({
  item,
  isActive,
  token,
  currentUserId,
  onLike,
  onFollow,
  onOpenComments,
}: {
  item: Reel;
  isActive: boolean;
  token: string | null;
  currentUserId: number | undefined;
  onLike: (reelId: number) => void;
  onFollow: (userId: number) => void;
  onOpenComments: (reelId: number) => void;
}) {
  const [liked, setLiked] = useState(item.is_liked);
  const [likesCount, setLikesCount] = useState(item.likes_count);
  const [following, setFollowing] = useState(item.is_following);
  const heartScale = useRef(new Animated.Value(1)).current;
  const doubleTapRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const bigHeartOpacity = useRef(new Animated.Value(0)).current;
  const bigHeartScale = useRef(new Animated.Value(0.5)).current;

  const player = useVideoPlayer(item.video_url, (p) => {
    p.loop = true;
    p.volume = 1;
  });

  useEffect(() => {
    if (isActive) {
      player.play();
    } else {
      player.pause();
    }
  }, [isActive]);

  useEffect(() => {
    setLiked(item.is_liked);
    setLikesCount(item.likes_count);
    setFollowing(item.is_following);
  }, [item.is_liked, item.likes_count, item.is_following]);

  const animateHeart = () => {
    Animated.sequence([
      Animated.timing(heartScale, { toValue: 1.4, duration: 100, useNativeDriver: true }),
      Animated.timing(heartScale, { toValue: 1, duration: 100, useNativeDriver: true }),
    ]).start();
  };

  const showBigHeart = () => {
    bigHeartOpacity.setValue(1);
    bigHeartScale.setValue(0.5);
    Animated.parallel([
      Animated.spring(bigHeartScale, { toValue: 1, friction: 3, useNativeDriver: true }),
      Animated.sequence([
        Animated.delay(600),
        Animated.timing(bigHeartOpacity, { toValue: 0, duration: 300, useNativeDriver: true }),
      ]),
    ]).start();
  };

  const handleLike = () => {
    const newLiked = !liked;
    setLiked(newLiked);
    setLikesCount(prev => newLiked ? prev + 1 : Math.max(prev - 1, 0));
    animateHeart();
    onLike(item.id);
  };

  const handleDoubleTap = () => {
    if (doubleTapRef.current) {
      clearTimeout(doubleTapRef.current);
      doubleTapRef.current = null;
      // Double tap - like
      if (!liked) {
        setLiked(true);
        setLikesCount(prev => prev + 1);
        animateHeart();
        onLike(item.id);
      }
      showBigHeart();
    } else {
      doubleTapRef.current = setTimeout(() => {
        doubleTapRef.current = null;
        // Single tap - toggle play/pause
        if (player.playing) {
          player.pause();
        } else {
          player.play();
        }
      }, 300);
    }
  };

  const handleFollow = () => {
    setFollowing(!following);
    onFollow(item.user_id);
  };

  const handleShare = async () => {
    try {
      await Share.share({
        message: `Check out this reel by @${item.username} on Crimzo!`,
        url: item.video_url,
      });
    } catch (e) { }
  };

  const formatCount = (n: number) => {
    if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
    if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
    return n.toString();
  };

  const isOwnReel = currentUserId === item.user_id;

  return (
    <View style={[styles.reelContainer, { height: REEL_HEIGHT }]}>
      <TouchableOpacity
        activeOpacity={1}
        onPress={handleDoubleTap}
        style={StyleSheet.absoluteFill}
      >
        <VideoView
          player={player}
          style={StyleSheet.absoluteFill}
          contentFit="cover"
          nativeControls={false}
        />
      </TouchableOpacity>

      {/* Bottom gradient */}
      <LinearGradient
        colors={['transparent', 'rgba(0,0,0,0.5)', 'rgba(0,0,0,0.85)']}
        style={styles.bottomGradient}
        pointerEvents="none"
      />

      {/* Top gradient */}
      <LinearGradient
        colors={['rgba(0,0,0,0.5)', 'transparent']}
        style={styles.topGradient}
        pointerEvents="none"
      />

      {/* Big heart animation (double tap) */}
      <Animated.View style={[styles.bigHeart, { opacity: bigHeartOpacity, transform: [{ scale: bigHeartScale }] }]} pointerEvents="none">
        <Ionicons name="heart" size={100} color="#FF2D55" />
      </Animated.View>

      {/* ΓöÇΓöÇ Right side actions ΓöÇΓöÇ */}
      <View style={styles.rightActions}>
        {/* Like */}
        <TouchableOpacity style={styles.actionBtn} onPress={handleLike}>
          <Animated.View style={{ transform: [{ scale: heartScale }] }}>
            <Ionicons
              name={liked ? 'heart' : 'heart-outline'}
              size={28}
              color={liked ? '#FF2D55' : '#FFF'}
            />
          </Animated.View>
          <Text style={styles.actionCount}>{formatCount(likesCount)}</Text>
        </TouchableOpacity>

        {/* Comment */}
        <TouchableOpacity style={styles.actionBtn} onPress={() => onOpenComments(item.id)}>
          <Ionicons name="chatbubble-outline" size={26} color="#FFF" />
          <Text style={styles.actionCount}>{formatCount(item.comments_count)}</Text>
        </TouchableOpacity>

        {/* Share */}
        <TouchableOpacity style={styles.actionBtn} onPress={handleShare}>
          <Ionicons name="paper-plane-outline" size={26} color="#FFF" />
        </TouchableOpacity>

        {/* More */}
        <TouchableOpacity style={styles.actionBtn}>
          <Ionicons name="ellipsis-vertical" size={22} color="#FFF" />
        </TouchableOpacity>
      </View>

      {/* ΓöÇΓöÇ Bottom info (Instagram-style) ΓöÇΓöÇ */}
      <View style={styles.bottomInfo}>
        {/* User row: avatar + username */}
        <View style={styles.userRow}>
          <TouchableOpacity style={styles.bottomAvatarWrap}>
            {item.avatar ? (
              <Image source={{ uri: item.avatar }} style={styles.bottomAvatar} />
            ) : (
              <View style={[styles.bottomAvatar, styles.bottomAvatarPlaceholder]}>
                <Ionicons name="person" size={16} color="#999" />
              </View>
            )}
          </TouchableOpacity>
          <Text style={styles.usernameText}>{item.username}</Text>
          {!isOwnReel && (
            <TouchableOpacity
              style={[styles.followBtn, following && styles.followingBtn]}
              onPress={handleFollow}
              activeOpacity={0.7}
            >
              <Text style={[styles.followBtnText, following && styles.followingBtnText]}>
                {following ? 'Following' : 'Follow'}
              </Text>
            </TouchableOpacity>
          )}
        </View>

        {/* Caption */}
        {item.caption ? (
          <Text style={styles.captionText} numberOfLines={2}>{item.caption}</Text>
        ) : null}

        {/* Stats row */}
        <View style={styles.statsRow}>
          <Ionicons name="heart" size={12} color="rgba(255,255,255,0.4)" />
          <Text style={styles.statsText}>{formatCount(likesCount)}</Text>
          <View style={styles.statsDot} />
          <Ionicons name="chatbubble" size={11} color="rgba(255,255,255,0.4)" />
          <Text style={styles.statsText}>{formatCount(item.comments_count)}</Text>
        </View>
      </View>
    </View>
  );
}

// ΓöÇΓöÇ Comments Bottom Sheet ΓöÇΓöÇ
function CommentsSheet({
  visible,
  reelId,
  token,
  onClose,
}: {
  visible: boolean;
  reelId: number | null;
  token: string | null;
  onClose: () => void;
}) {
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loading, setLoading] = useState(false);
  const [posting, setPosting] = useState(false);
  const slideAnim = useRef(new Animated.Value(SCREEN_HEIGHT)).current;

  useEffect(() => {
    if (visible && reelId) {
      Animated.spring(slideAnim, { toValue: 0, damping: 20, stiffness: 150, useNativeDriver: true }).start();
      fetchComments();
    } else {
      Animated.timing(slideAnim, { toValue: SCREEN_HEIGHT, duration: 250, useNativeDriver: true }).start();
    }
  }, [visible, reelId]);

  const fetchComments = async () => {
    if (!reelId || !token) return;
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/reels/${reelId}/comments`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (data.success) setComments(data.comments);
    } catch (e) {
      console.error('Fetch comments error:', e);
    } finally {
      setLoading(false);
    }
  };

  const postComment = async () => {
    if (!newComment.trim() || !reelId || !token || posting) return;
    setPosting(true);
    try {
      const res = await fetch(`${API_URL}/api/reels/${reelId}/comment`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ text: newComment.trim() }),
      });
      const data = await res.json();
      if (data.success) {
        setComments(prev => [data.comment, ...prev]);
        setNewComment('');
      }
    } catch (e) {
      console.error('Post comment error:', e);
    } finally {
      setPosting(false);
    }
  };

  const timeAgo = (dateStr: string) => {
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'now';
    if (mins < 60) return `${mins}m`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d`;
    return `${Math.floor(days / 7)}w`;
  };

  if (!visible) return null;

  return (
    <Animated.View style={[styles.commentsOverlay, { transform: [{ translateY: slideAnim }] }]}>
      <TouchableOpacity style={styles.commentsBackdrop} onPress={onClose} activeOpacity={1} />
      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
        style={styles.commentsSheet}
      >
        {/* Handle */}
        <View style={styles.sheetHandle}>
          <View style={styles.sheetHandleBar} />
        </View>

        <View style={styles.commentsHeader}>
          <Text style={styles.commentsTitle}>Comments</Text>
          <TouchableOpacity onPress={onClose}>
            <Ionicons name="close" size={24} color="#FFF" />
          </TouchableOpacity>
        </View>

        {loading ? (
          <View style={styles.commentsLoading}>
            <ActivityIndicator size="small" color="#FF2D55" />
          </View>
        ) : comments.length === 0 ? (
          <View style={styles.noComments}>
            <Ionicons name="chatbubble-outline" size={40} color="#555" />
            <Text style={styles.noCommentsText}>No comments yet</Text>
            <Text style={styles.noCommentsSubtext}>Be the first to comment!</Text>
          </View>
        ) : (
          <FlatList
            data={comments}
            keyExtractor={(c) => c.id.toString()}
            style={styles.commentsList}
            renderItem={({ item: c }) => (
              <View style={styles.commentItem}>
                {c.avatar ? (
                  <Image source={{ uri: c.avatar }} style={styles.commentAvatar} />
                ) : (
                  <View style={[styles.commentAvatar, styles.commentAvatarPlaceholder]}>
                    <Ionicons name="person" size={14} color="#999" />
                  </View>
                )}
                <View style={styles.commentBody}>
                  <View style={styles.commentNameRow}>
                    <Text style={styles.commentUsername}>{c.username}</Text>
                    <Text style={styles.commentTime}>{timeAgo(c.created_at)}</Text>
                  </View>
                  <Text style={styles.commentText}>{c.text}</Text>
                </View>
              </View>
            )}
          />
        )}

        {/* Input */}
        <View style={styles.commentInputRow}>
          <TextInput
            style={styles.commentInput}
            placeholder="Add a comment..."
            placeholderTextColor="#666"
            value={newComment}
            onChangeText={setNewComment}
            multiline
            maxLength={500}
          />
          <TouchableOpacity
            style={[styles.sendBtn, !newComment.trim() && styles.sendBtnDisabled]}
            onPress={postComment}
            disabled={!newComment.trim() || posting}
          >
            {posting ? (
              <ActivityIndicator size="small" color="#FFF" />
            ) : (
              <Ionicons name="send" size={20} color={newComment.trim() ? '#FFF' : '#666'} />
            )}
          </TouchableOpacity>
        </View>
      </KeyboardAvoidingView>
    </Animated.View>
  );
}

// ΓöÇΓöÇ Main Reels Screen ΓöÇΓöÇ
export default function ReelsScreen() {
  const { token, user } = useAuth();
  const [reels, setReels] = useState<Reel[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [activeIndex, setActiveIndex] = useState(0);
  const [commentsVisible, setCommentsVisible] = useState(false);
  const [commentReelId, setCommentReelId] = useState<number | null>(null);
  const [screenFocused, setScreenFocused] = useState(true);

  // ΓöÇΓöÇ Reel upload state ΓöÇΓöÇ
  const [showReelUpload, setShowReelUpload] = useState(false);
  const [uploadAsset, setUploadAsset] = useState<any>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploadDone, setUploadDone] = useState(false);

  const fetchReels = useCallback(async () => {
    if (!token) { setLoading(false); setRefreshing(false); return; }
    try {
      const res = await fetch(`${API_URL}/api/reels/feed?limit=50`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      if (data.success && Array.isArray(data.reels)) {
        setReels(data.reels);
      }
    } catch (e) {
      console.error('Fetch reels error:', e);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [token]);

  useEffect(() => {
    fetchReels();
  }, [fetchReels]);

  // Refetch when screen comes back into focus (picks up newly uploaded reels)
  useFocusEffect(
    useCallback(() => {
      setScreenFocused(true);
      fetchReels();
      return () => setScreenFocused(false);
    }, [fetchReels])
  );

  const handleLike = async (reelId: number) => {
    if (!token) return;
    try {
      await fetch(`${API_URL}/api/reels/${reelId}/like`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      });
    } catch (e) {
      console.error('Like error:', e);
    }
  };

  const handleFollow = async (userId: number) => {
    if (!token) return;
    try {
      await fetch(`${API_URL}/api/user/follow`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ userId }),
      });
    } catch (e) {
      console.error('Follow error:', e);
    }
  };

  const handleViewReel = async (reelId: number) => {
    if (!token) return;
    try {
      await fetch(`${API_URL}/api/reels/${reelId}/view`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      });
    } catch (e) { }
  };

  const onOpenComments = (reelId: number) => {
    setCommentReelId(reelId);
    setCommentsVisible(true);
  };

  const onViewableItemsChanged = useRef(({ viewableItems }: any) => {
    if (viewableItems.length > 0) {
      const newIndex = viewableItems[0].index;
      setActiveIndex(newIndex);
      // Record view
      const viewedReel = viewableItems[0].item;
      if (viewedReel) {
        handleViewReel(viewedReel.id);
      }
    }
  }).current;

  const viewabilityConfig = useRef({
    viewAreaCoveragePercentThreshold: 50,
  }).current;

  const onRefresh = () => {
    setRefreshing(true);
    fetchReels();
  };

  // ΓöÇΓöÇ Reel upload from reels tab ΓöÇΓöÇ
  const handlePickReel = async () => {
    try {
      const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
      if (status !== 'granted') {
        return;
      }
      const result = await ImagePicker.launchImageLibraryAsync({
        mediaTypes: ['videos'],
        allowsEditing: true,
        quality: 0.8,
        videoMaxDuration: 60,
      });
      if (result.canceled || !result.assets?.length) return;
      setUploadAsset(result.assets[0]);
      setShowReelUpload(true);
    } catch (e) {
      console.error('Pick reel error:', e);
    }
  };

  const uploadReelFile = async (caption: string) => {
    if (!uploadAsset || !token) return;
    setUploading(true);
    setUploadProgress(10);
    setUploadDone(false);
    try {
      const formData = new FormData();
      formData.append('video', {
        uri: uploadAsset.uri,
        type: 'video/mp4',
        name: 'reel.mp4',
      } as any);
      formData.append('caption', caption || '');

      const response = await axios.post(
        `${API_URL}/api/reels/upload`,
        formData,
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'multipart/form-data',
          },
          timeout: 5 * 60 * 1000,
          onUploadProgress: (evt) => {
            if (evt.total && evt.total > 0) {
              const pct = Math.round((evt.loaded / evt.total) * 95);
              setUploadProgress(Math.min(95, Math.max(10, pct)));
            } else {
              setUploadProgress(prev => prev < 70 ? prev + 2 : prev);
            }
          },
        }
      );

      if (response.data.success) {
        setUploadProgress(100);
        setUploadDone(true);
        setTimeout(() => {
          setUploading(false);
          setUploadDone(false);
          setShowReelUpload(false);
          setUploadAsset(null);
          fetchReels();
        }, 1200);
      } else {
        throw new Error('Failed to save reel');
      }
    } catch (error: any) {
      console.error('Reel upload error:', error.response?.data || error.message);
      setUploading(false);
      alert(error.response?.data?.error || error.message || 'Upload failed');
    }
  };

  if (loading) {
    return (
      <View style={styles.loadingContainer}>
        <StatusBar barStyle="light-content" />
        <ActivityIndicator size="large" color="#FF2D55" />
        <Text style={styles.loadingText}>Loading Reels...</Text>
      </View>
    );
  }

  if (reels.length === 0) {
    return (
      <View style={styles.emptyContainer}>
        <StatusBar barStyle="light-content" />
        <View style={styles.emptyHeader}>
          <Text style={styles.headerTitle}>Reels</Text>
          <TouchableOpacity style={styles.uploadHeaderBtn} onPress={handlePickReel}>
            <Ionicons name="add-circle-outline" size={26} color="#FF2D55" />
          </TouchableOpacity>
        </View>
        <View style={styles.emptyContent}>
          <Ionicons name="film-outline" size={64} color="#555" />
          <Text style={styles.emptyTitle}>No Reels Yet</Text>
          <Text style={styles.emptySubtext}>Be the first to share a reel!</Text>
          <TouchableOpacity style={[styles.emptyBtn, { backgroundColor: '#FF2D55', marginBottom: 12 }]} onPress={handlePickReel}>
            <Ionicons name="cloud-upload-outline" size={18} color="#FFF" />
            <Text style={styles.emptyBtnText}>Upload Reel</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.emptyBtn} onPress={onRefresh}>
            <Ionicons name="refresh" size={18} color="#FFF" />
            <Text style={styles.emptyBtnText}>Refresh</Text>
          </TouchableOpacity>
        </View>
        <ReelUploadModal
          visible={showReelUpload}
          asset={uploadAsset}
          uploading={uploading}
          uploadProgress={uploadProgress}
          uploadDone={uploadDone}
          onClose={() => { if (!uploading) { setShowReelUpload(false); setUploadAsset(null); } }}
          onPost={uploadReelFile}
        />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />

      {/* Header overlay */}
      <View style={styles.headerOverlay}>
        <Text style={styles.reelsTitle}>Reels</Text>
        <TouchableOpacity style={styles.uploadHeaderBtn} onPress={handlePickReel}>
          <Ionicons name="add-circle-outline" size={26} color="#FFF" />
        </TouchableOpacity>
      </View>

      <FlatList
        data={reels}
        keyExtractor={(item) => item.id.toString()}
        renderItem={({ item, index }) => (
          <ReelItem
            item={item}
            isActive={index === activeIndex && screenFocused && !commentsVisible}
            token={token}
            currentUserId={user?.id}
            onLike={handleLike}
            onFollow={handleFollow}
            onOpenComments={onOpenComments}
          />
        )}
        pagingEnabled
        snapToInterval={REEL_HEIGHT}
        snapToAlignment="start"
        decelerationRate="fast"
        showsVerticalScrollIndicator={false}
        onViewableItemsChanged={onViewableItemsChanged}
        viewabilityConfig={viewabilityConfig}
        getItemLayout={(_, index) => ({
          length: REEL_HEIGHT,
          offset: REEL_HEIGHT * index,
          index,
        })}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor="#FF2D55" progressViewOffset={60} />
        }
        removeClippedSubviews
        maxToRenderPerBatch={3}
        windowSize={5}
      />

      {/* Comments Sheet */}
      <CommentsSheet
        visible={commentsVisible}
        reelId={commentReelId}
        token={token}
        onClose={() => {
          setCommentsVisible(false);
          setCommentReelId(null);
        }}
      />

      {/* Reel Upload Modal */}
      <ReelUploadModal
        visible={showReelUpload}
        asset={uploadAsset}
        uploading={uploading}
        uploadProgress={uploadProgress}
        uploadDone={uploadDone}
        onClose={() => { if (!uploading) { setShowReelUpload(false); setUploadAsset(null); } }}
        onPost={uploadReelFile}
      />
    </View>
  );
}

