import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Alert,
  ActivityIndicator,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useRouter, useLocalSearchParams } from 'expo-router';
import { useAuth } from '../../contexts/AuthContext';
import { Ionicons } from '@expo/vector-icons';
import axios from 'axios';

const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;

export default function PKBattleScreen() {
  const { mode, battleId } = useLocalSearchParams();
  const { user, token } = useAuth();
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [battleData, setBattleData] = useState<any>(null);
  const [isActive, setIsActive] = useState(false);
  const [host1Score, setHost1Score] = useState(0);
  const [host2Score, setHost2Score] = useState(0);
  const [timeRemaining, setTimeRemaining] = useState(300); // 5 minutes

  useEffect(() => {
    if (mode === 'create') {
      createBattle();
    } else if (mode === 'join' && battleId) {
      joinBattle();
    }
  }, [mode, battleId]);

  const createBattle = async () => {
    setLoading(true);
    try {
      console.log('Creating PK Battle...');
      const response = await axios.post(
        `${API_URL}/api/pk/create`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );

      console.log('Battle created:', response.data);
      setBattleData(response.data);
      setIsActive(response.data.status === 'active');
      Alert.alert('Battle Created', 'Waiting for opponent...');
    } catch (error: any) {
      console.error('Create battle error:', error);
      Alert.alert('Error', 'Failed to create battle');
      router.back();
    } finally {
      setLoading(false);
    }
  };

  const joinBattle = async () => {
    setLoading(true);
    try {
      console.log('Joining PK Battle:', battleId);
      const response = await axios.post(
        `${API_URL}/api/pk/join/${battleId}`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );

      console.log('Joined battle:', response.data);
      setBattleData(response.data);
      setIsActive(true);
      Alert.alert('Joined!', 'PK Battle has started!');
    } catch (error: any) {
      console.error('Join battle error:', error);
      Alert.alert('Error', 'Failed to join battle');
      router.back();
    } finally {
      setLoading(false);
    }
  };

  const endBattle = async () => {
    if (!battleData?.battleId) return;

    try {
      await axios.post(
        `${API_URL}/api/pk/end/${battleData.battleId}`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );

      Alert.alert('Battle Ended', 'PK Battle has ended!', [
        { text: 'OK', onPress: () => router.back() }
      ]);
    } catch (error: any) {
      console.error('End battle error:', error);
    }
  };

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <ActivityIndicator size="large" color="#FF2D55" />
        <Text style={styles.loadingText}>Setting up battle...</Text>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      {/* Header */}
      <View style={styles.header}>
        <TouchableOpacity onPress={endBattle}>
          <Ionicons name="close" size={28} color="#FFF" />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>PK BATTLE</Text>
        <Text style={styles.timer}>{Math.floor(timeRemaining / 60)}:{(timeRemaining % 60).toString().padStart(2, '0')}</Text>
      </View>

      {/* Battle Arena - Split Screen */}
      <View style={styles.battleArena}>
        {/* Host 1 Side */}
        <View style={[styles.hostSide, styles.host1Side]}>
          <View style={styles.hostVideo}>
            <Ionicons name="person" size={48} color="#FF2D55" />
            <Text style={styles.hostLabel}>Host 1</Text>
          </View>
          <View style={styles.scoreContainer}>
            <Text style={styles.scoreLabel}>Score</Text>
            <Text style={styles.scoreValue}>{host1Score}</Text>
          </View>
        </View>

        {/* VS Divider */}
        <View style={styles.vsDivider}>
          <View style={styles.vsCircle}>
            <Text style={styles.vsText}>VS</Text>
          </View>
        </View>

        {/* Host 2 Side */}
        <View style={[styles.hostSide, styles.host2Side]}>
          <View style={styles.hostVideo}>
            {isActive ? (
              <>
                <Ionicons name="person" size={48} color="#30D158" />
                <Text style={styles.hostLabel}>Host 2</Text>
              </>
            ) : (
              <>
                <Ionicons name="hourglass" size={48} color="#666" />
                <Text style={styles.hostLabel}>Waiting...</Text>
              </>
            )}
          </View>
          <View style={styles.scoreContainer}>
            <Text style={styles.scoreLabel}>Score</Text>
            <Text style={styles.scoreValue}>{host2Score}</Text>
          </View>
        </View>
      </View>

      {/* Gift Panel */}
      <View style={styles.giftPanel}>
        <Text style={styles.giftTitle}>Send Gifts to Support</Text>
        <View style={styles.gifts}>
          {[10, 50, 100, 500].map((value) => (
            <TouchableOpacity
              key={value}
              style={styles.giftButton}
              onPress={() => {
                Alert.alert('Gift Sent', `Sent ${value} coins!`);
                // Update scores here
              }}
            >
              <Ionicons name="gift" size={24} color="#FFD700" />
              <Text style={styles.giftValue}>{value}</Text>
            </TouchableOpacity>
          ))}
        </View>
      </View>

      {/* Controls */}
      <View style={styles.controls}>
        <TouchableOpacity style={styles.endButton} onPress={endBattle}>
          <Ionicons name="stop-circle" size={24} color="#FFF" />
          <Text style={styles.endButtonText}>End Battle</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

