import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  ActivityIndicator,
  RefreshControl,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useRouter } from 'expo-router';
import { useAuth } from '../../contexts/AuthContext';
import { Ionicons } from '@expo/vector-icons';
import axios from 'axios';

const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;

export default function PKLobbyScreen() {
  const { token } = useAuth();
  const router = useRouter();
  const [battles, setBattles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  useEffect(() => {
    fetchBattles();
  }, []);

  const fetchBattles = async () => {
    try {
      const response = await axios.get(`${API_URL}/api/pk/active`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setBattles(response.data.battles || []);
    } catch (error) {
      console.error('Fetch battles error:', error);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  const onRefresh = () => {
    setRefreshing(true);
    fetchBattles();
  };

  const handleCreateBattle = () => {
    router.push('/pk/battle?mode=create');
  };

  const handleJoinBattle = (battleId: string) => {
    router.push(`/pk/battle?mode=join&battleId=${battleId}`);
  };

  const renderBattleCard = (battle: any) => {
    const isWaiting = battle.status === 'waiting';
    
    return (
      <View key={battle.id} style={styles.battleCard}>
        {isWaiting && (
          <View style={styles.waitingBadge}>
            <Text style={styles.waitingText}>LOOKING FOR OPPONENT</Text>
          </View>
        )}
        
        <View style={styles.battleHeader}>
          <View style={styles.battleIcon}>
            <Ionicons name="flash" size={24} color="#FF9500" />
          </View>
          <Text style={styles.battleTitle}>PK Battle</Text>
          <View style={styles.participants}>
            <Ionicons name="people" size={16} color="#999" />
            <Text style={styles.participantsText}>
              {battle.host2_id ? '2' : '1'} / 2
            </Text>
          </View>
        </View>

        <View style={styles.battleInfo}>
          <View style={styles.hostInfo}>
            <Ionicons name="person-circle" size={32} color="#FF2D55" />
            <Text style={styles.hostName}>{battle.host1_username}</Text>
          </View>
          
          {battle.host2_id ? (
            <View style={styles.hostInfo}>
              <Ionicons name="person-circle" size={32} color="#30D158" />
              <Text style={styles.hostName}>{battle.host2_username}</Text>
            </View>
          ) : (
            <View style={styles.emptyHost}>
              <Ionicons name="help-circle" size={32} color="#666" />
              <Text style={styles.emptyText}>Waiting...</Text>
            </View>
          )}
        </View>

        <View style={styles.battleDuration}>
          <Ionicons name="time-outline" size={16} color="#999" />
          <Text style={styles.durationText}>{battle.duration || 300}s</Text>
        </View>

        {isWaiting && (
          <TouchableOpacity
            style={styles.joinButton}
            onPress={() => handleJoinBattle(battle.battle_id)}
          >
            <Text style={styles.joinButtonText}>Join as Host</Text>
          </TouchableOpacity>
        )}
      </View>
    );
  };

  return (
    <SafeAreaView style={styles.container}>
      {/* Header */}
      <View style={styles.header}>
        <TouchableOpacity onPress={() => router.back()}>
          <Ionicons name="arrow-back" size={24} color="#FFF" />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>PK Battle Lobby</Text>
        <View style={{ width: 24 }} />
      </View>

      {/* Create Button */}
      <TouchableOpacity style={styles.createButton} onPress={handleCreateBattle}>
        <Ionicons name="add" size={24} color="#FFF" />
        <Text style={styles.createButtonText}>Create PK Battle</Text>
      </TouchableOpacity>

      {/* Active Battles Section */}
      <Text style={styles.sectionTitle}>Active Battles</Text>

      {loading ? (
        <ActivityIndicator size="large" color="#FF2D55" style={styles.loader} />
      ) : (
        <ScrollView
          style={styles.battlesList}
          refreshControl={
            <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor="#FF2D55" />
          }
        >
          {battles.length > 0 ? (
            battles.map(renderBattleCard)
          ) : (
            <View style={styles.emptyState}>
              <Ionicons name="flash-off-outline" size={64} color="#666" />
              <Text style={styles.emptyStateText}>No active battles</Text>
              <Text style={styles.emptyStateSubtext}>Be the first to create one!</Text>
            </View>
          )}
        </ScrollView>
      )}
    </SafeAreaView>
  );
}

