import React, { useState, useEffect, useCallback } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  FlatList,
  Image,
  StatusBar,
  ActivityIndicator,
  TextInput,
  KeyboardAvoidingView,
  Platform,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useRouter } from 'expo-router';
import { useAuth } from '../../contexts/AuthContext';

const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;

type Message = {
  id: number;
  sender_id: number;
  receiver_id: number;
  content: string;
  sender_username: string;
  sender_avatar: string | null;
  is_read: boolean;
  created_at: string;
};

type Conversation = {
  user_id: number;
  username: string;
  avatar: string | null;
  last_message: string;
  last_time: string;
  unread_count: number;
  is_online: boolean;
};

export default function MessagesScreen() {
  const { user, token } = useAuth();
  const router = useRouter();
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedChat, setSelectedChat] = useState<Conversation | null>(null);
  const [chatMessages, setChatMessages] = useState<Message[]>([]);
  const [chatLoading, setChatLoading] = useState(false);
  const [newMessage, setNewMessage] = useState('');
  const [sending, setSending] = useState(false);

  const fetchConversations = useCallback(async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/messages/conversations`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (data.success) {
        setConversations(data.conversations || []);
      }
    } catch (e) {
      console.error('Fetch conversations error:', e);
    } finally {
      setLoading(false);
    }
  }, [token]);

  useEffect(() => {
    fetchConversations();
  }, []);

  const openChat = async (conv: Conversation) => {
    setSelectedChat(conv);
    setChatLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/messages/${conv.user_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (data.success) {
        setChatMessages(data.messages || []);
      }
    } catch (e) {
      console.error('Fetch messages error:', e);
    } finally {
      setChatLoading(false);
    }
  };

  const sendMessage = async () => {
    if (!newMessage.trim() || !selectedChat || sending) return;
    setSending(true);
    const msgText = newMessage.trim();
    setNewMessage('');

    // Optimistic update
    const optimistic: Message = {
      id: Date.now(),
      sender_id: user?.id || 0,
      receiver_id: selectedChat.user_id,
      content: msgText,
      sender_username: user?.username || '',
      sender_avatar: user?.avatar || null,
      is_read: false,
      created_at: new Date().toISOString(),
    };
    setChatMessages(prev => [...prev, optimistic]);

    try {
      const res = await fetch(`${API_URL}/api/messages/send`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          receiverId: selectedChat.user_id,
          content: msgText,
        }),
      });
      const data = await res.json();
      if (data.success && data.message) {
        setChatMessages(prev =>
          prev.map(m => (m.id === optimistic.id ? data.message : m))
        );
      }
    } catch (e) {
      console.error('Send message error:', e);
    } finally {
      setSending(false);
    }
  };

  const getTimeAgo = (ts: string) => {
    const diff = Date.now() - new Date(ts).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Now';
    if (mins < 60) return `${mins}m`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d`;
    return new Date(ts).toLocaleDateString();
  };

  // ΓöÇΓöÇ Chat Detail View ΓöÇΓöÇ
  if (selectedChat) {
    return (
      <View style={styles.container}>
        <StatusBar barStyle="light-content" />
        <View style={styles.header}>
          <TouchableOpacity onPress={() => setSelectedChat(null)} style={styles.backBtn}>
            <Ionicons name="arrow-back" size={24} color="#FFF" />
          </TouchableOpacity>
          <View style={styles.headerCenter}>
            <Text style={styles.headerTitle}>{selectedChat.username}</Text>
            {selectedChat.is_online && (
              <Text style={styles.onlineText}>Online</Text>
            )}
          </View>
          <View style={{ width: 40 }} />
        </View>

        <KeyboardAvoidingView
          behavior={Platform.OS === 'ios' ? 'padding' : undefined}
          style={{ flex: 1 }}
          keyboardVerticalOffset={0}
        >
          {chatLoading ? (
            <View style={styles.centerFull}>
              <ActivityIndicator size="large" color="#FF2D55" />
            </View>
          ) : chatMessages.length === 0 ? (
            <View style={styles.centerFull}>
              <Ionicons name="chatbubble-ellipses-outline" size={60} color="#333" />
              <Text style={styles.emptyText}>No messages yet</Text>
              <Text style={styles.emptySubtext}>Say hi!</Text>
            </View>
          ) : (
            <FlatList
              data={chatMessages}
              keyExtractor={(item) => item.id.toString()}
              contentContainerStyle={{ padding: 16, paddingBottom: 20 }}
              renderItem={({ item }) => {
                const isMe = item.sender_id === user?.id;
                return (
                  <View style={[styles.msgRow, isMe && styles.msgRowMe]}>
                    {!isMe && (
                      item.sender_avatar ? (
                        <Image source={{ uri: item.sender_avatar }} style={styles.msgAvatar} />
                      ) : (
                        <View style={[styles.msgAvatar, styles.msgAvatarPlaceholder]}>
                          <Ionicons name="person" size={14} color="#999" />
                        </View>
                      )
                    )}
                    <View style={[styles.msgBubble, isMe ? styles.myBubble : styles.theirBubble]}>
                      <Text style={[styles.msgText, isMe && { color: '#FFF' }]}>{item.content}</Text>
                      <Text style={[styles.msgTime, isMe && { color: 'rgba(255,255,255,0.5)' }]}>
                        {getTimeAgo(item.created_at)}
                      </Text>
                    </View>
                  </View>
                );
              }}
            />
          )}

          {/* Input */}
          <View style={styles.inputBar}>
            <TextInput
              style={styles.textInput}
              value={newMessage}
              onChangeText={setNewMessage}
              placeholder="Type a message..."
              placeholderTextColor="#666"
              maxLength={500}
            />
            <TouchableOpacity
              onPress={sendMessage}
              disabled={!newMessage.trim() || sending}
              style={[styles.sendBtn, newMessage.trim() && styles.sendBtnActive]}
            >
              <Ionicons
                name="send"
                size={20}
                color={newMessage.trim() ? '#FFF' : '#555'}
              />
            </TouchableOpacity>
          </View>
        </KeyboardAvoidingView>
      </View>
    );
  }

  // ΓöÇΓöÇ Conversations List ΓöÇΓöÇ
  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" />
      <View style={styles.header}>
        <TouchableOpacity onPress={() => router.back()} style={styles.backBtn}>
          <Ionicons name="arrow-back" size={24} color="#FFF" />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>Messages</Text>
        <View style={{ width: 40 }} />
      </View>

      {loading ? (
        <View style={styles.centerFull}>
          <ActivityIndicator size="large" color="#FF2D55" />
        </View>
      ) : conversations.length === 0 ? (
        <View style={styles.centerFull}>
          <Ionicons name="chatbubbles-outline" size={70} color="#222" />
          <Text style={styles.emptyText}>No messages yet</Text>
          <Text style={styles.emptySubtext}>
            Follow streamers and start chatting!
          </Text>
        </View>
      ) : (
        <FlatList
          data={conversations}
          keyExtractor={(item) => item.user_id.toString()}
          contentContainerStyle={{ paddingBottom: 40 }}
          renderItem={({ item }) => (
            <TouchableOpacity
              style={styles.convItem}
              onPress={() => openChat(item)}
              activeOpacity={0.6}
            >
              <View style={styles.convAvatarWrap}>
                {item.avatar ? (
                  <Image source={{ uri: item.avatar }} style={styles.convAvatar} />
                ) : (
                  <View style={[styles.convAvatar, styles.convAvatarPlaceholder]}>
                    <Ionicons name="person" size={22} color="#999" />
                  </View>
                )}
                {item.is_online && (
                  <View style={styles.convOnline}>
                    <View style={styles.convOnlineDot} />
                  </View>
                )}
              </View>
              <View style={styles.convInfo}>
                <View style={styles.convTop}>
                  <Text style={styles.convName}>{item.username}</Text>
                  <Text style={styles.convTime}>{getTimeAgo(item.last_time)}</Text>
                </View>
                <View style={styles.convBottom}>
                  <Text style={styles.convMsg} numberOfLines={1}>{item.last_message}</Text>
                  {item.unread_count > 0 && (
                    <View style={styles.unreadBadge}>
                      <Text style={styles.unreadText}>{item.unread_count}</Text>
                    </View>
                  )}
                </View>
              </View>
            </TouchableOpacity>
          )}
        />
      )}

      {/* System Messages */}
      <View style={styles.systemSection}>
        <TouchableOpacity style={styles.systemItem}>
          <View style={[styles.systemIcon, { backgroundColor: 'rgba(255,45,85,0.15)' }]}>
            <Ionicons name="megaphone" size={20} color="#FF2D55" />
          </View>
          <View style={styles.systemInfo}>
            <Text style={styles.systemName}>Crimzo Team</Text>
            <Text style={styles.systemMsg}>Welcome to Crimzo! ≡ƒÄë</Text>
          </View>
          <Ionicons name="chevron-forward" size={18} color="#444" />
        </TouchableOpacity>
      </View>
    </View>
  );
}

