import React, { useState, useEffect, useRef, useCallback } from 'react';
import {
    View,
    Text,
    StyleSheet,
    Image,
    TouchableOpacity,
    Modal,
    Dimensions,
    StatusBar,
    Animated,
    Easing,
    ActivityIndicator,
    PanResponder,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { Video, ResizeMode } from 'expo-av';
import { useSafeAreaInsets } from 'react-native-safe-area-context';

const { width: SW, height: SH } = Dimensions.get('window');
const STORY_DURATION = 5000; // 5 seconds per photo story

interface Story {
    id: number;
    media_url: string;
    media_type: 'photo' | 'video';
    caption: string;
    created_at: string;
    expires_at: string;
}

interface StoryGroup {
    user_id: number;
    username: string;
    avatar: string | null;
    stories: Story[];
}

interface Props {
    visible: boolean;
    storyGroups: StoryGroup[];
    initialGroupIndex: number;
    currentUserId: number;
    onClose: () => void;
    onDeleteStory?: (storyId: number) => void;
}

function getTimeAgo(dateStr: string): string {
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return `${mins} min ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    return `${Math.floor(hrs / 24)}d ago`;
}

function useCurrentTime() {
    const [, setTick] = React.useState(0);
    useEffect(() => {
        const iv = setInterval(() => setTick(t => t + 1), 30000);
        return () => clearInterval(iv);
    }, []);
}

export default function StoryViewer({ visible, storyGroups, initialGroupIndex, currentUserId, onClose, onDeleteStory }: Props) {
    const insets = useSafeAreaInsets();
    useCurrentTime(); // triggers re-render every 30s to update timeAgo
    const [groupIndex, setGroupIndex] = useState(initialGroupIndex);
    const [storyIndex, setStoryIndex] = useState(0);
    const [paused, setPaused] = useState(false);
    const [imageLoading, setImageLoading] = useState(true);
    const progressAnim = useRef(new Animated.Value(0)).current;
    const progressAnimation = useRef<Animated.CompositeAnimation | null>(null);
    const videoRef = useRef<Video>(null);

    const currentGroup = storyGroups[groupIndex];
    const currentStory = currentGroup?.stories?.[storyIndex];
    const isOwn = currentGroup?.user_id === currentUserId;

    // Reset when opening or changing initial group
    useEffect(() => {
        if (visible) {
            setGroupIndex(initialGroupIndex);
            setStoryIndex(0);
            setPaused(false);
        }
    }, [visible, initialGroupIndex]);

    // Animate progress bar
    useEffect(() => {
        if (!visible || !currentStory || paused) return;

        progressAnim.setValue(0);
        const duration = currentStory.media_type === 'video' ? 15000 : STORY_DURATION;

        const anim = Animated.timing(progressAnim, {
            toValue: 1,
            duration,
            easing: Easing.linear,
            useNativeDriver: false,
        });
        progressAnimation.current = anim;

        anim.start(({ finished }) => {
            if (finished) {
                goNext();
            }
        });

        return () => {
            anim.stop();
        };
    }, [visible, groupIndex, storyIndex, paused, imageLoading]);

    const goNext = useCallback(() => {
        if (!currentGroup) return;
        if (storyIndex < currentGroup.stories.length - 1) {
            setStoryIndex(storyIndex + 1);
            setImageLoading(true);
        } else if (groupIndex < storyGroups.length - 1) {
            setGroupIndex(groupIndex + 1);
            setStoryIndex(0);
            setImageLoading(true);
        } else {
            onClose();
        }
    }, [storyIndex, groupIndex, currentGroup, storyGroups.length, onClose]);

    const goPrev = useCallback(() => {
        if (storyIndex > 0) {
            setStoryIndex(storyIndex - 1);
            setImageLoading(true);
        } else if (groupIndex > 0) {
            setGroupIndex(groupIndex - 1);
            const prevGroup = storyGroups[groupIndex - 1];
            setStoryIndex(prevGroup.stories.length - 1);
            setImageLoading(true);
        }
    }, [storyIndex, groupIndex, storyGroups]);

    const handlePress = useCallback((evt: any) => {
        const x = evt.nativeEvent.locationX;
        if (x < SW * 0.35) {
            goPrev();
        } else {
            goNext();
        }
    }, [goPrev, goNext]);

    // Swipe down to close
    const panResponder = useRef(
        PanResponder.create({
            onStartShouldSetPanResponder: () => false,
            onMoveShouldSetPanResponder: (_, gs) => Math.abs(gs.dy) > 20 && Math.abs(gs.dy) > Math.abs(gs.dx),
            onPanResponderRelease: (_, gs) => {
                if (gs.dy > 80) {
                    onClose();
                }
            },
        })
    ).current;

    const handleDelete = useCallback(() => {
        if (currentStory && onDeleteStory) {
            onDeleteStory(currentStory.id);
            // Move to next story or close
            if (currentGroup.stories.length <= 1) {
                onClose();
            } else {
                goNext();
            }
        }
    }, [currentStory, onDeleteStory, currentGroup, goNext, onClose]);

    if (!visible || !currentGroup || !currentStory) return null;

    return (
        <Modal visible={visible} transparent animationType="fade" onRequestClose={onClose} statusBarTranslucent>
            <StatusBar barStyle="light-content" backgroundColor="transparent" translucent />
            <View style={styles.container} {...panResponder.panHandlers}>
                {/* ΓöÇΓöÇ Media Background ΓöÇΓöÇ */}
                <TouchableOpacity
                    activeOpacity={1}
                    onPress={handlePress}
                    onLongPress={() => setPaused(true)}
                    onPressOut={() => setPaused(false)}
                    style={StyleSheet.absoluteFill}
                >
                    {currentStory.media_type === 'video' ? (
                        <Video
                            ref={videoRef}
                            source={{ uri: currentStory.media_url }}
                            style={styles.media}
                            resizeMode={ResizeMode.CONTAIN}
                            shouldPlay={!paused}
                            isLooping={false}
                            onPlaybackStatusUpdate={(status: any) => {
                                if (status.didJustFinish) goNext();
                            }}
                            onLoad={() => setImageLoading(false)}
                        />
                    ) : (
                        <Image
                            source={{ uri: currentStory.media_url }}
                            style={styles.media}
                            resizeMode="contain"
                            onLoadEnd={() => setImageLoading(false)}
                        />
                    )}
                </TouchableOpacity>

                {imageLoading && (
                    <View style={styles.loaderOverlay}>
                        <ActivityIndicator size="large" color="#FF2D55" />
                    </View>
                )}

                {/* ΓöÇΓöÇ Progress Bars ΓöÇΓöÇ */}
                <View style={[styles.progressRow, { top: insets.top + 8 }]}>
                    {currentGroup.stories.map((_, i) => (
                        <View key={i} style={styles.progressTrack}>
                            <Animated.View
                                style={[
                                    styles.progressFill,
                                    {
