import React, { useEffect, useRef } from 'react';
import { View, Text, Animated, Easing, StyleSheet } from 'react-native';

interface Props {
  visible: boolean;
  progress?: number;   // 0-100
  done?: boolean;
  message?: string;
}

const UploadOverlay: React.FC<Props> = ({
  visible,
  progress = 0,
  done = false,
  message = 'Uploading...',
}) => {
  const barWidth = useRef(new Animated.Value(0)).current;
  const checkScale = useRef(new Animated.Value(0)).current;
  const spinAnim = useRef(new Animated.Value(0)).current;

  // Animate the progress bar width
  useEffect(() => {
    Animated.timing(barWidth, {
      toValue: progress,
      duration: 300,
      useNativeDriver: false,
    }).start();
  }, [progress]);

  // Pop in the checkmark when done
  useEffect(() => {
    if (done) {
      Animated.spring(checkScale, {
        toValue: 1,
        friction: 4,
        tension: 80,
        useNativeDriver: true,
      }).start();
    } else {
      checkScale.setValue(0);
    }
  }, [done]);

  // Spinning ring animation
  useEffect(() => {
    if (visible && !done) {
      Animated.loop(
        Animated.timing(spinAnim, {
          toValue: 1,
          duration: 1000,
          easing: Easing.linear,
          useNativeDriver: true,
        })
      ).start();
    } else {
      spinAnim.setValue(0);
    }
  }, [visible, done]);

  if (!visible) return null;

  const spin = spinAnim.interpolate({ inputRange: [0, 1], outputRange: ['0deg', '360deg'] });
  const barPercent = barWidth.interpolate({ inputRange: [0, 100], outputRange: ['0%', '100%'], extrapolate: 'clamp' });

  return (
    <View style={styles.overlay}>
      <View style={styles.box}>
        {done ? (
          <Animated.View style={[styles.checkCircle, { transform: [{ scale: checkScale }] }]}>
            <Text style={styles.checkMark}>Γ£ô</Text>
          </Animated.View>
        ) : (
          <Animated.View style={[styles.spinRing, { transform: [{ rotate: spin }] }]} />
        )}

        <Text style={styles.title}>{done ? 'Upload Complete!' : message}</Text>

        {!done && (
          <>
            <View style={styles.progressTrack}>
              <Animated.View style={[styles.progressFill, { width: barPercent }]} />
            </View>
            <Text style={styles.progressText}>{Math.min(100, Math.round(progress))}%</Text>
          </>
        )}
      </View>
    </View>
  );
};

