export default LiveStreamGrid;

import React, { useRef, useEffect } from 'react';
import { View, Animated, Easing, StyleSheet } from 'react-native';

const PulsingLiveDot: React.FC = () => {
    const pulseAnim = useRef(new Animated.Value(1)).current;
    const opacityAnim = useRef(new Animated.Value(0.6)).current;

    useEffect(() => {
        Animated.loop(
            Animated.parallel([
                Animated.sequence([
                    Animated.timing(pulseAnim, { toValue: 1.8, duration: 1000, easing: Easing.inOut(Easing.ease), useNativeDriver: true }),
                    Animated.timing(pulseAnim, { toValue: 1, duration: 1000, easing: Easing.inOut(Easing.ease), useNativeDriver: true }),
                ]),
                Animated.sequence([
                    Animated.timing(opacityAnim, { toValue: 0, duration: 1000, useNativeDriver: true }),
                    Animated.timing(opacityAnim, { toValue: 0.6, duration: 1000, useNativeDriver: true }),
                ]),
            ])
        ).start();
    }, []);

    return (
        <View style={styles.container}>
            <Animated.View
                style={[
                    styles.pulse,
                    { transform: [{ scale: pulseAnim }], opacity: opacityAnim },
                ]}
            />
            <View style={styles.dot} />
        </View>
    );
};

const styles = StyleSheet.create({
    container: { position: 'absolute', top: -2, right: -2, width: 16, height: 16, alignItems: 'center', justifyContent: 'center', zIndex: 5 },
    pulse: { position: 'absolute', width: 16, height: 16, borderRadius: 8, backgroundColor: '#FF2D55' },
    dot: { width: 8, height: 8, borderRadius: 4, backgroundColor: '#FF2D55', borderWidth: 1.5, borderColor: '#000' },
});

export default PulsingLiveDot;

import React, { createContext, useState, useContext, useEffect, useRef } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import axios from 'axios';
import { Alert } from 'react-native';

const API_URL = process.env.EXPO_PUBLIC_BACKEND_URL;

// ΓöÇΓöÇ Aggressive backend warmup (Render free tier cold starts = 30-50s) ΓöÇΓöÇ
// Fire immediately + retry at 5s and 15s to guarantee server is awake before login
let _backendReady = false;
const warmupBackend = () => {
  const ping = () =>
    fetch(`${API_URL}/api/health`, { method: 'GET' })
      .then(() => { _backendReady = true; })
      .catch(() => { });
  ping();
  setTimeout(ping, 5000);
  setTimeout(ping, 15000);
};
warmupBackend();

interface User {
  id: number;
  email: string;
  username: string;
  avatar?: string;
  bio?: string;
  country: string;
  diamonds: number;
  beans: number;
  followers_count: number;
  following_count: number;
  friends_count: number;
  is_online: boolean;
  status: string;
}

interface AuthContextType {
  user: User | null;
  token: string | null;
  loading: boolean;
  isGuest: boolean;
  login: (email: string, password: string) => Promise<void>;
  emailLogin: (email: string) => Promise<void>;
  register: (email: string, password: string, username: string, avatarUri?: string) => Promise<void>;
  guestLogin: () => Promise<void>;
  testLogin: () => Promise<void>;
  sendPhoneOtp: (phone: string) => Promise<void>;
  verifyPhoneOtp: (phone: string, otp: string) => Promise<void>;
  sendEmailOtp: (email: string) => Promise<void>;
  verifyEmailOtp: (email: string, otp: string) => Promise<{ isNewUser: boolean }>;
  completeEmailRegistration: (email: string, username: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  updateUser: (userData: Partial<User>) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [isGuest, setIsGuest] = useState(false);

  useEffect(() => {
    loadStoredAuth();
  }, []);

  const loadStoredAuth = async () => {
    try {
      // Use multiGet for faster parallel read (instead of 3 separate getItem calls)
      const keys = ['auth_token', 'is_guest', 'cached_user'];
      const stores = await AsyncStorage.multiGet(keys);
      const storedToken = stores[0][1];
      const storedGuest = stores[1][1];
      const storedUser = stores[2][1];

      if (storedToken) {
        setToken(storedToken);
        if (storedGuest === 'true') setIsGuest(true);
        // Restore cached user INSTANTLY so app doesn't wait for network
        if (storedUser) {
          try { setUser(JSON.parse(storedUser)); } catch (_) { }
        }
        // Mark loading done immediately ΓÇö user is restored from cache
        setLoading(false);
        // Refresh user data in background (non-blocking)
        fetchUser(storedToken);
        return;
      }
    } catch (error) {
      console.error('Load auth error:', error);
    }
    setLoading(false);
  };

  const fetchUser = async (authToken: string) => {
    try {
      const response = await axios.get(`${API_URL}/api/auth/me`, {
        headers: { Authorization: `Bearer ${authToken}` },
        timeout: 10000,
      });
      setUser(response.data);
      // Update cache in background (non-blocking)
      AsyncStorage.setItem('cached_user', JSON.stringify(response.data)).catch(() => { });
    } catch (error: any) {
      const status = error.response?.status;
      if (status === 401 || status === 403) {
        await logout();
      }
      // Network errors: keep session alive silently
    }
  };

  // ΓöÇΓöÇ Helper: save auth to state + storage in parallel ΓöÇΓöÇ
  const persistAuth = (authToken: string, userData: any, guest = false) => {
    setToken(authToken);
    setUser(userData);
    setIsGuest(guest);
    // Write to AsyncStorage in parallel (non-blocking for faster UX)
    const pairs: [string, string][] = [
      ['auth_token', authToken],
      ['cached_user', JSON.stringify(userData)],
    ];
    if (guest) pairs.push(['is_guest', 'true']);
    AsyncStorage.multiSet(pairs).catch(() => { });
    if (!guest) AsyncStorage.removeItem('is_guest').catch(() => { });
  };

  const login = async (email: string, password: string) => {
    try {
      const normalizedEmail = email.trim().toLowerCase();
      console.log('Attempting login...', { email: normalizedEmail, API_URL });
      const response = await axios.post(`${API_URL}/api/auth/login`, {
        email: normalizedEmail,
        password
      }, { timeout: 15000 });

      console.log('Login response:', response.data);
      persistAuth(response.data.token, response.data.user);
    } catch (error: any) {
      console.error('Login error:', error.response?.data || error.message);
      if (error.code === 'ECONNABORTED') {
        throw new Error('Server is waking up. Please wait a moment and try again.');
      }
      const errorMsg = error.response?.data?.error || error.message || 'Login failed. Please check your connection.';
      throw new Error(errorMsg);
    }
  };

  const register = async (email: string, password: string, username: string, avatarUri?: string) => {
    try {
      const normalizedEmail = email.trim().toLowerCase();
      console.log('Attempting registration...', { email: normalizedEmail, username, hasAvatar: !!avatarUri, API_URL });

      // Always use FormData so multer middleware can parse fields correctly
      const formData = new FormData();
      formData.append('email', normalizedEmail);
      formData.append('password', password);
      formData.append('username', username.trim());

      if (avatarUri) {
        const filename = avatarUri.split('/').pop() || `avatar_${Date.now()}.jpg`;
        formData.append('avatar', { uri: avatarUri, name: filename, type: 'image/jpeg' } as any);
      }

      // Do NOT set Content-Type manually ΓÇö let React Native set it with the correct boundary
      const response = await axios.post(`${API_URL}/api/auth/register`, formData, {
        timeout: 30000,
      });

      console.log('Registration response:', response.data);
      persistAuth(response.data.token, response.data.user);
    } catch (error: any) {
      console.error('Registration error:', error.response?.data || error.message);
      if (error.code === 'ECONNABORTED') {
        throw new Error('Server is waking up. Please wait a moment and try again.');
      }
      throw new Error(error.response?.data?.error || error.message || 'Registration failed. Please check your connection.');
    }
  };

  const logout = async () => {
    await AsyncStorage.multiRemove(['auth_token', 'is_guest', 'cached_user']);
    setToken(null);
    setUser(null);
    setIsGuest(false);
  };

  // ΓöÇΓöÇ Email Login (for Gmail/Google accounts stored in DB ΓÇö no password needed) ΓöÇΓöÇ
  const emailLogin = async (email: string) => {
    try {
      const normalizedEmail = email.trim().toLowerCase();
      console.log('Attempting email login (google endpoint)...', { email: normalizedEmail });
      const response = await axios.post(`${API_URL}/api/auth/google`, {
        email: normalizedEmail,
      }, { timeout: 15000 });
      persistAuth(response.data.token, response.data.user);
    } catch (error: any) {
      console.error('Email login error:', error.response?.data || error.message);
      throw new Error(error.response?.data?.error || 'Login failed. Please check your email.');
    }
  };

  // ΓöÇΓöÇ Test Login (dev only ΓÇö no OTP, no server) ΓöÇΓöÇ
  const testLogin = async () => {
    try {
      const response = await axios.post(`${API_URL}/api/auth/guest`, {}, { timeout: 15000 });
      const userData = { ...response.data.user, username: 'DevTestUser', diamonds: 5000 };
      persistAuth(response.data.token, userData);
    } catch (e) {
      console.error('TestLogin failed, backend may be offline:', e);
      Alert.alert('Dev Login Failed', 'Backend is offline. Start the backend server first.');
    }
  };

  // ΓöÇΓöÇ Guest Login ΓöÇΓöÇ
  const guestLogin = async () => {
    try {
      console.log('Attempting guest login...', { API_URL });
      const response = await axios.post(`${API_URL}/api/auth/guest`, {}, { timeout: 15000 });
      persistAuth(response.data.token, response.data.user, true);
    } catch (error: any) {
      console.error('Guest login error:', error.response?.data || error.message);
      throw new Error(error.response?.data?.error || 'Guest login failed. Check your connection.');
    }
  };


  // ΓöÇΓöÇ Phone OTP ΓöÇΓöÇ
  const sendPhoneOtp = async (phone: string) => {
    try {
      console.log('Sending OTP to:', phone);
      await axios.post(`${API_URL}/api/auth/phone/send-otp`, { phone }, { timeout: 15000 });
      console.log('OTP sent successfully');
    } catch (error: any) {
      console.error('Send OTP error:', error.response?.data || error.message);
      throw new Error(error.response?.data?.error || 'Failed to send OTP.');
    }
  };

  const verifyPhoneOtp = async (phone: string, otp: string) => {
    try {
      console.log('Verifying OTP for:', phone);
      const response = await axios.post(`${API_URL}/api/auth/phone/verify-otp`, { phone, otp }, { timeout: 15000 });
      persistAuth(response.data.token, response.data.user);
    } catch (error: any) {
      console.error('Verify OTP error:', error.response?.data || error.message);
      throw new Error(error.response?.data?.error || 'OTP verification failed.');
    }
  };

  const updateUser = (userData: Partial<User>) => {
    if (user) {
      const updated = { ...user, ...userData };
      setUser(updated);
      // Sync cache in background
      AsyncStorage.setItem('cached_user', JSON.stringify(updated)).catch(() => { });
    }
  };

  // ΓöÇΓöÇ Email OTP: Send ΓöÇΓöÇ
  const sendEmailOtp = async (email: string) => {
    try {
      await axios.post(`${API_URL}/api/auth/email/send-otp`, { email: email.trim().toLowerCase() }, { timeout: 15000 });
    } catch (error: any) {
      throw new Error(error.response?.data?.error || 'Failed to send OTP to email.');
    }
  };

  // ΓöÇΓöÇ Email OTP: Verify ΓöÇΓöÇ
  const verifyEmailOtp = async (email: string, otp: string): Promise<{ isNewUser: boolean }> => {
    try {
      const response = await axios.post(`${API_URL}/api/auth/email/verify-otp`, {
        email: email.trim().toLowerCase(),
        otp,
      }, { timeout: 15000 });
      const { isNewUser, token: authToken, user: userData } = response.data;
      if (!isNewUser && authToken) {
        persistAuth(authToken, userData);
      }
      return { isNewUser };
    } catch (error: any) {
      throw new Error(error.response?.data?.error || 'OTP verification failed.');
    }
  };

  // ΓöÇΓöÇ Email OTP: Complete Registration ΓöÇΓöÇ
  const completeEmailRegistration = async (email: string, username: string, password: string) => {
    try {
      const response = await axios.post(`${API_URL}/api/auth/email/complete-registration`, {
        email: email.trim().toLowerCase(),
        username: username.trim(),
        password,
      }, { timeout: 15000 });
      persistAuth(response.data.token, response.data.user);
    } catch (error: any) {
      throw new Error(error.response?.data?.error || 'Registration failed.');
    }
  };

  return (
    <AuthContext.Provider value={{ user, token, loading, isGuest, login, emailLogin, register, guestLogin, testLogin, sendPhoneOtp, verifyPhoneOtp, sendEmailOtp, verifyEmailOtp, completeEmailRegistration, logout, updateUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
};
